using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains and evaluates the ticket classification model at startup,
/// then saves it for use by PredictionEnginePool.
/// </summary>
public class TicketModelTrainer : IHostedService
{
    private readonly ILogger<TicketModelTrainer> _logger;
    private readonly ModelLabelStore _labelStore;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger, IWebHostEnvironment env, ModelLabelStore labelStore)
    {
        _logger = logger;
        _labelStore = labelStore;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split 80/20 for train/test
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

        // Build pipeline: featurize text columns, combine with Priority, then classify
        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("Confusion Matrix:\n{ConfusionMatrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Extract label names from Score column to map probabilities correctly
        var scoreColumn = predictions.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        _labelStore.Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        _logger.LogInformation("Label order: {Labels}", string.Join(", ", _labelStore.Labels));

        // Save model
        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

